#!/bin/bash
set -e

GREEN='\033[0;32m'; BLUE='\033[0;34m'; YELLOW='\033[1;33m'; RED='\033[0;31m'; NC='\033[0m'

echo ""
echo -e "${BLUE}⚡ BatteryAlert v4.0 — Install${NC}"
echo "──────────────────────────────"
echo ""

if ! command -v xcodebuild &> /dev/null; then
    echo -e "${RED}✗ Xcode not found. Install it from the App Store.${NC}"; exit 1
fi
echo -e "${GREEN}✓ Xcode detected${NC}"

MACOS_VERSION=$(sw_vers -productVersion | cut -d. -f1)
if [ "$MACOS_VERSION" -lt 13 ]; then
    echo -e "${RED}✗ macOS 13+ required.${NC}"; exit 1
fi
echo -e "${GREEN}✓ macOS $(sw_vers -productVersion)${NC}"

WORKDIR=$(mktemp -d)
APPNAME="BatteryAlert"
PROJECT_DIR="$WORKDIR/$APPNAME"
SOURCES_DIR="$PROJECT_DIR/$APPNAME"
mkdir -p "$SOURCES_DIR"

echo -e "${BLUE}→ Creating project files...${NC}"

# Decode and run the embedded Python writer (contains all source files as base64)
WRITER_B64=""
echo "$WRITER_B64" | base64 --decode > /tmp/ba_writer_$$.py
python3 /tmp/ba_writer_$$.py "$SOURCES_DIR" "$PROJECT_DIR"
rm -f /tmp/ba_writer_$$.py

echo -e "${BLUE}→ Generating app icon...${NC}"
ASSETS_DIR="$SOURCES_DIR/Assets.xcassets/AppIcon.appiconset"
for size in 16 32 64 128 256 512 1024; do
    sips -z $size $size "$ASSETS_DIR/icon_src.png" --out "$ASSETS_DIR/icon_${size}.png" > /dev/null 2>&1
done
rm -f "$ASSETS_DIR/icon_src.png"
echo -e "${GREEN}✓ App icon generated${NC}"

echo -e "${BLUE}→ Compiling (~30 seconds)...${NC}"
BUILD_DIR="$WORKDIR/build"

xcodebuild \
    -project "$PROJECT_DIR/$APPNAME.xcodeproj" \
    -scheme "$APPNAME" \
    -configuration Release \
    -derivedDataPath "$BUILD_DIR" \
    CODE_SIGN_IDENTITY="-" \
    CODE_SIGNING_REQUIRED=NO \
    CODE_SIGNING_ALLOWED=NO \
    ONLY_ACTIVE_ARCH=YES \
    > "$WORKDIR/build.log" 2>&1

if [ $? -ne 0 ]; then
    echo -e "${RED}✗ Compilation failed:${NC}"
    tail -50 "$WORKDIR/build.log"
    echo ""
    echo "Full log saved at: $WORKDIR/build.log"
    exit 1
fi
echo -e "${GREEN}✓ Compilation successful${NC}"

APP_PATH=$(find "$BUILD_DIR" -name "BatteryAlert.app" -type d | head -1)
if [ -z "$APP_PATH" ]; then
    echo -e "${RED}✗ App not found after build.${NC}"; exit 1
fi

echo -e "${BLUE}→ Creating .dmg...${NC}"
DMG_DIR="$WORKDIR/dmg_content"
mkdir -p "$DMG_DIR"
cp -R "$APP_PATH" "$DMG_DIR/"
ln -s /Applications "$DMG_DIR/Applications"
DMG_PATH="$HOME/Desktop/BatteryAlert.dmg"

hdiutil create -volname "BatteryAlert" -srcfolder "$DMG_DIR" -ov -format UDZO "$DMG_PATH" > /dev/null 2>&1
if [ $? -ne 0 ]; then
    echo -e "${YELLOW}⚠ DMG failed, installing directly to /Applications...${NC}"
    cp -R "$APP_PATH" /Applications/
    echo -e "${GREEN}✓ BatteryAlert installed in /Applications${NC}"
else
    echo -e "${GREEN}✓ BatteryAlert.dmg created on your Desktop!${NC}"
fi

rm -rf "$WORKDIR"

echo ""
echo -e "${GREEN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
echo -e "${GREEN}  ✅ Done! BatteryAlert v4.0${NC}"
echo -e "${GREEN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
echo ""
echo "  Open BatteryAlert.dmg on your Desktop,"
echo "  drag to Applications, and launch."
echo ""
